module top_module(
    q,
    reset_clk,
    rst
);output reg [3:0] q;
    input reset_clk;
    input rst;

    always @(posedge reset_clk) begin
        if (rst) begin
            q <= 4'b0000;
        end else begin
            q <= q + 1;
            if (q == 4'b1111) begin
                q <= 4'b0000;
            end
        end
    end

endmodule
